B.Ur=s(["4\xd7 Krinner U-FIX 91 an den angezeichneten Punkten ansetzen.","Mit einem Stahlstab durch die Aufnahme lotrecht eindrehen.","Mit der Wasserwaage an der H\xfclse laufend die Senkrechte kontrollieren.","Die 4 Aufnahmen grob auf gleiche H\xf6he bringen (Feinausgleich folgt \xfcber die Bolzen)."],t.s)
B.Tn=s(["assets/bau/03_erdschraube_lot.png"],t.s)
B.Il=new A.i8("erdschrauben","Erdschrauben eindrehen",B.Ur,"Jede Erdschraube lotrecht; Positionen = angezeichnetes Rechteck.","Auf Steine/Wurzeln achten \u2013 notfalls Schraube leicht versetzen, das Rechteck aber halten.",B.Tn)
B.Us=s(["4 Pfosten aus Douglasie 90\xd790 auf ~120 mm zuschneiden.","Je Pfosten in eine U-FIX-Aufnahme stellen.","Seitlich mit 8\xd7100-Schraube durchbolzen."],t.s)
B.SH=s(["assets/bau/04_pfosten_ufix.png"],t.s)
B.Ih=new A.i8("pfosten","Pfosten setzen",B.Us,"Pfosten fest, grob gleiche Oberkante.",null,B.SH)
B.Tg=s(["In jeden Pfostenkopf mittig 16 mm bohren (Forstner-/Holzbohrer).","Einschlagmutter M16 b\xfcndig einsetzen.","Sechskantschraube M16\xd7100 eindrehen, grosse Auflagescheibe auflegen.","Kontermutter aufsetzen, aber noch NICHT kontern (Feinjustage folgt beim Nivellieren)."],t.s)
B.uB=s(["assets/bau/05_nivellierbolzen.png"],t.s)
B.Ii=new A.i8("nivellierbolzen","Nivellier-Bolzen einbauen",B.Tg,"Schraube leichtg\xe4ngig, Scheibe plan, Verstellweg \xb125 mm frei.",null,B.uB)
B.VS=s(["Die 2 Doppelbalken auf die 4 Auflagescheiben legen (Achse 400 mm).","Mit Kreuzlinienlaser oder Schlauchwaage die 4 Bolzen in EINE Ebene drehen \u2013 in L\xe4ngs- UND Querrichtung waagerecht.","Kontermuttern fest anziehen.","Jeden Balken mit 2 Schwerlast-Winkeln (90\xd790\xd765) auf den Pfosten sichern (8 Winkel gesamt)."],t.s)
B.RD=s(["assets/bau/06_querschnitt_aufbau.png","assets/bau/05_nivellierbolzen.png"],t.s)
B.Ik=new A.i8("nivellieren","Balken auflegen & nivellieren",B.VS,"Balken-Oberkante waagerecht l\xe4ngs UND quer; Kontermuttern fest.","Schl\xfcsselschritt \u2013 hier entsteht die ebene, r\xfcckenschonende H\xf6he. Ruhig mehrfach nachmessen.",B.RD)
B.SE=s(["4 Platten 560 \xd7 500 mm aus der Schaltafel zuschneiden (falls nicht im Markt geschnitten).","Alle Schnittkanten SOFORT versiegeln (Hirnholz zuerst) \u2013 gr\xf6sster Langlebigkeits-Faktor.","Je Platte 2\u20134 Entw\xe4sserungsl\xf6cher \xd8 8 mm bohren."],t.s)
B.SW=s(["assets/bau/07_platte_entwaesserung.png"],t.s)
B.Iq=new A.i8("platten_zuschnitt","Platten zuschneiden & versiegeln",B.SE,"Kanten rundum versiegelt; L\xf6cher gebohrt.",null,B.SW)
B.T3=s(["Je Platte mittig \xfcber beide Balken legen (fasst die Waage 500\xd7430 mit Rand).","Von oben mit Terrassenschraube A2 5\xd750 verschrauben (steift den Stand aus).","Jede Platte mit der Wasserwaage pr\xfcfen."],t.s)
