B.Io=new A.i8("oel","\xd6len & lasieren",B.Um,"Kein blankes Hirnholz mehr; alle Fl\xe4chen behandelt.","Unbehandeltes Douglasie ist bienenfreundlich \u2013 nur aussen/Kanten sch\xfctzen, keine Biozide an der Beute.",B.uD)
B.TN=s(["HiveWatch-Waage je Platte LOSE auflegen \u2013 nichts seitlich \xfcberbr\xfccken (keine Steine/Leisten).","3-m-Kabel in einer Kantennut am Pfosten herabf\xfchren, Logger gesch\xfctzt platzieren.","Waagen tarieren.","Beuten aufsetzen (Reihenfolge Platte \u2192 Waage \u2192 Beute), Flugrichtung S\xfcdost pr\xfcfen, kalibrieren."],t.s)
